class Solution {
    public int minMovesToMakePalindrome(String s) {
        int n = s.length();
        int res = 0;
        int l = 0, r = n - 1;
        while (l < r) {
            if (s.charAt(l) != s.charAt(r)) {
                int k = r;
                while (s.charAt(l) != s.charAt(k)) k--;
                String t = s.substring(k, r + 1);
                s = s.substring(0, k) + t + s.substring(r + 1);
                res += r - k;
            }
            l++;
            r--;
        }
        return res;
    }
}
```
